import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty for empty input");
  it.todo("should kill a single live cell (underpopulation)");
  it.todo("should kill two adjacent live cells (underpopulation, rule 1)");
  it.todo("should keep a block stable (still life)");
  it.todo("should let a live cell with 3 neighbors survive (rule 2)");
  it.todo("should kill a live cell with more than 3 neighbors (rule 3, overpopulation)");
  it.todo("should bring a dead cell with exactly 3 neighbors to life (rule 4, reproduction)");
  it.todo("should oscillate a vertical blinker to a horizontal blinker");
});
